INSERT INTO Devices (
    device_id, user_id, model_name, hard_limit_per_dose
) VALUES (
    #{deviceId}, #{userId}, #{modelName}, #{hardLimitPerDose}
)

INSERT INTO ClinicalLogs (
    user_id, device_id, glucose_level, last_dose_amount, last_dose_time, injection_status
) VALUES (
    #{userId}, #{deviceId}, #{glucoseLevel}, #{lastDoseAmount}, CURRENT_TIMESTAMP, #{injectionStatus}
)
